13	// TriageClassification values returned by the complexity evaluator.
14	const (
15		TriageClassificationAtomic       = "atomic"
16		TriageClassificationDecomposable = "decomposable"
17		TriageClassificationAmbiguous    = "ambiguous"
18	)
19	
20	// DefaultMaxDecompositionDepth is the default recursion cap for triage gate
21	// splitting. Configurable via agent.triage.max_decomposition_depth in
22	// .ddx/config.yaml.
23	const DefaultMaxDecompositionDepth = 3
24	
25	// TriageSkipLabel on a bead bypasses the complexity gate without classifying.
26	const TriageSkipLabel = "triage:skip"
27	
28	// TriageDepthKey is the bead Extra field key that tracks decomposition depth.
29	// Children filed by the gate inherit depth+1 from their parent.
30	const TriageDepthKey = "triage.depth"
31	
32	// ChildBeadSpec describes one child bead produced by the splitter prompt.
33	type ChildBeadSpec struct {
34		Title        string   `json:"title"`
35		Description  string   `json:"description,omitempty"`
36		Acceptance   string   `json:"acceptance,omitempty"`
37		Labels       []string `json:"labels,omitempty"`
38		SpecID       string   `json:"spec_id,omitempty"`
39		InScopeFiles []string `json:"in_scope_files,omitempty"`
40	}
41	
42	// TriageGate is called for each candidate bead between RoutePreflight and Claim.
43	// Returns (true, nil) when the bead is atomic and should proceed to Claim.
44	// Returns (false, nil) when the gate handled the bead (decomposed or surfaced
45	// for human triage). Returns (false, err) on a gate error — the loop logs the
46	// error and skips the bead without claiming.
47	type TriageGate func(ctx context.Context, candidate bead.Bead) (shouldClaim bool, err error)
48	
49	// ComplexityClassifier classifies a bead as atomic, decomposable, or ambiguous.
50	// Returns the classification string, a confidence in [0,1], and a human-readable
51	// reasoning string.
52	type ComplexityClassifier func(ctx context.Context, b bead.Bead) (classification string, confidence float64, reasoning string, err error)
53	
54	// BeadSplitter decomposes a decomposable bead into child specs.
55	type BeadSplitter func(ctx context.Context, b bead.Bead) (children []ChildBeadSpec, rationale string, err error)
56	
57	// TriageStore is the store interface required by the triage gate for child
58	// filing and parent mutation. *bead.Store satisfies this interface.
59	type TriageStore interface {
60		Create(b *bead.Bead) error
61		Update(id string, fn func(*bead.Bead)) error
62		AppendEvent(id string, ev bead.BeadEvent) error
63	}
64	
65	// NewComplexityGate constructs a TriageGate that evaluates each candidate bead
66	// for decomposition before Claim. Behaviour by classification:
67	//   - atomic:       returns shouldClaim=true, caller proceeds to Claim.
68	//   - decomposable: files child beads, sets parent status=blocked, returns
69	//     shouldClaim=false.
70	//   - ambiguous:    sets execution-eligible=false, appends triage-ambiguous
71	//     event, returns shouldClaim=false.
72	//
73	// At depth cap: emits kind:triage-overflow, sets status=blocked with
74	// label=needs-human-decomposition, returns shouldClaim=false without calling
75	// the classifier.
76	//
77	// A nil gate (not using NewComplexityGate) causes the loop to skip triage and
78	// emit a one-time boot warning per Run() invocation.
79	func NewComplexityGate(classifier ComplexityClassifier, splitter BeadSplitter, store TriageStore, maxDepth int, now func() time.Time) TriageGate {
80		if maxDepth <= 0 {
81			maxDepth = DefaultMaxDecompositionDepth
82		}
83		if now == nil {
84			now = time.Now
85		}
86		return func(ctx context.Context, candidate bead.Bead) (bool, error) {
87			// triage:skip bypasses the gate entirely — bead proceeds to Claim.
88			if HasBeadLabel(candidate.Labels, TriageSkipLabel) {
89				return true, nil
90			}
91	
92			depth := triageDepth(candidate)
93	
94			// At depth cap: park for human intervention, never dispatch.
95			if depth >= maxDepth {
96				body, _ := json.Marshal(map[string]any{"depth": depth, "max": maxDepth})
97				_ = store.AppendEvent(candidate.ID, bead.BeadEvent{
98					Kind:      "triage-overflow",
99					Summary:   fmt.Sprintf("decomposition depth cap reached (%d)", maxDepth),
100					Body:      string(body),
101					Actor:     "ddx",
102					Source:    "ddx triage gate",
103					CreatedAt: now().UTC(),
104				})
105				_ = store.Update(candidate.ID, func(b *bead.Bead) {
106					b.Status = bead.StatusBlocked
107					if b.Extra == nil {
108						b.Extra = make(map[string]any)
109					}
110					b.Extra["triage_block_reason"] = "needs-human-decomposition"
111					if !HasBeadLabel(b.Labels, "needs-human-decomposition") {
112						b.Labels = append(b.Labels, "needs-human-decomposition")
113					}
114				})
115				return false, nil
116			}
117	
118			classification, confidence, reasoning, err := classifier(ctx, candidate)
119			if err != nil {
120				return false, fmt.Errorf("triage classifier: %w", err)
121			}
122	
123			switch classification {
124			case TriageClassificationAtomic:
125				return true, nil
126	
127			case TriageClassificationAmbiguous:
128				body, _ := json.Marshal(map[string]any{
129					"confidence": confidence,
130					"reasoning":  reasoning,
131				})
132				_ = store.AppendEvent(candidate.ID, bead.BeadEvent{
133					Kind:      "triage-ambiguous",
134					Summary:   "triage: ambiguous — needs human review",
135					Body:      string(body),
136					Actor:     "ddx",
137					Source:    "ddx triage gate",
138					CreatedAt: now().UTC(),
139				})
140				_ = store.Update(candidate.ID, func(b *bead.Bead) {
141					if b.Extra == nil {
142						b.Extra = make(map[string]any)
143					}
144					b.Extra["execution-eligible"] = false
145					b.Extra["triage_block_reason"] = "ambiguous"
146					if !HasBeadLabel(b.Labels, "triage:needs-human") {
147						b.Labels = append(b.Labels, "triage:needs-human")
148					}
149				})
150				return false, nil
151	
152			case TriageClassificationDecomposable:
153				children, rationale, err := splitter(ctx, candidate)
154				if err != nil {
155					return false, fmt.Errorf("triage splitter: %w", err)
156				}
157				childIDs, err := fileChildren(store, candidate, children, depth, now)
158				if err != nil {
159					return false, err
160				}
161				blockParentDecomposed(store, candidate.ID, childIDs, rationale, now)
162				return false, nil
163			}
164	
165			// Unknown classification falls through to Claim.
166			return true, nil
167		}
168	}
169	
170	// triageDepth reads the current decomposition depth from a bead's Extra field.
171	// JSON numbers unmarshal as float64; the switch handles all common numeric types.
172	func triageDepth(b bead.Bead) int {
173		if b.Extra == nil {
174			return 0
175		}
176		switch v := b.Extra[TriageDepthKey].(type) {
177		case int:
178			return v
179		case float64:
180			return int(v)
181		case int64:
182			return int(v)
183		case json.Number:
184			n, _ := v.Int64()
185			return int(n)
186		}
187		return 0
188	}
