190	// fileChildren creates child beads in the store and returns their IDs.
191	func fileChildren(store TriageStore, parent bead.Bead, specs []ChildBeadSpec, parentDepth int, now func() time.Time) ([]string, error) {
192		childIDs := make([]string, 0, len(specs))
193		for _, spec := range specs {
194			labels := make([]string, len(spec.Labels))
195			copy(labels, spec.Labels)
196	
197			extra := map[string]any{TriageDepthKey: parentDepth + 1}
198	
199			// Inherit spec-id from parent.
200			if parent.Extra != nil {
201				if specID, ok := parent.Extra["spec-id"]; ok && specID != "" {
202					extra["spec-id"] = specID
203				}
204			}
205			if spec.SpecID != "" {
206				extra["spec-id"] = spec.SpecID
207			}
208	
209			child := &bead.Bead{
210				Title:       spec.Title,
211				Description: spec.Description,
212				Acceptance:  spec.Acceptance,
213				Labels:      labels,
214				Parent:      parent.ID,
215				Extra:       extra,
216			}
217			if err := store.Create(child); err != nil {
218				return nil, fmt.Errorf("triage: file child bead %q: %w", spec.Title, err)
219			}
220			childIDs = append(childIDs, child.ID)
221		}
222		return childIDs, nil
223	}
