316	// RuleBasedClassifier is a heuristic ComplexityClassifier used by the
317	// TriagePrompts tests to validate the eval corpus without requiring a live LLM.
318	// It matches keywords derived from the complexity-eval prompt criteria.
319	func RuleBasedClassifier(_ context.Context, b bead.Bead) (string, float64, string, error) {
320		text := strings.ToLower(b.Title + " " + b.Description + " " + b.Acceptance)
321	
322		decomposableKWs := []string{
323			"all crud", "complete suite", "multiple ", "all endpoints", "all operations",
324			"batch ", "matrix ", "initial tranche", "full system", "migrate all",
325			"monitoring, alerting", "phase 1", "phase 2", "part 1", "part 2",
326			"and dashboard", "scaffolding", "full migration", "epic", "all services",
327			"step 1", "step 2", "auth system", "infrastructure", "suite of",
328		}
329		atomicKWs := []string{
330			"fix nil", "fix bug", "add flag", "add --", "bump ", "update default",
331			"rename ", "single file", "one endpoint", "one method",
332		}
333	
334		decomScore := 0
335		for _, kw := range decomposableKWs {
336			if strings.Contains(text, kw) {
337				decomScore++
338			}
339		}
340		atomicScore := 0
341		for _, kw := range atomicKWs {
342			if strings.Contains(text, kw) {
343				atomicScore++
344			}
345		}
346	
347		if decomScore >= 2 && decomScore > atomicScore {
348			return TriageClassificationDecomposable, 0.82, "multiple deliverables detected", nil
349		}
350		return TriageClassificationAtomic, 0.87, "focused single-deliverable task", nil
351	}
