1290	// reCommitSHA matches a 7-to-40 character lowercase hex string that looks like a
1291	// git commit SHA. Used to detect whether a no_changes rationale cites a prior commit.
1292	var reCommitSHA = regexp.MustCompile(`\b[0-9a-f]{7,40}\b`)
1293	
1294	// reTestFuncName matches a Go test function name (TestXxx or BenchmarkXxx).
1295	var reTestFuncName = regexp.MustCompile(`\b(?:Test|Benchmark)[A-Z]\w*\b`)
1296	
1297	// rationaleIsSpecific returns true when the rationale string contains a reference
1298	// specific enough to treat a no_changes outcome as already_satisfied on the first
1299	// attempt. Currently this means: the rationale cites a commit SHA (7+ hex chars)
1300	// or a Go test function name. Vague rationales ("nothing to do") return false.
1301	func rationaleIsSpecific(rationale string) bool {
1302		if rationale == "" {
1303			return false
1304		}
1305		return reCommitSHA.MatchString(rationale) || reTestFuncName.MatchString(rationale)
1306	}
1307	
1308	// adjudicateNoChanges runs the no-change adjudication step for a bead.
1309	// It returns (satisfied, evidence, err). When satisfied is true the bead
1310	// should be closed as already_satisfied with the evidence string. When false
1311	// retry suppression (cooldown) should be applied and the bead left open.
1312	//
1313	// If a SatisfactionChecker is configured it is called first. Otherwise:
1314	//   - When the report carries a specific rationale (cites a commit SHA or test
1315	//     name), the bead is closed as already_satisfied on the first occurrence.
1316	//   - Otherwise the default count-based rule applies (close after maxNoChangesBeforeClose).
1317	func (w *ExecuteBeadWorker) adjudicateNoChanges(ctx context.Context, beadID string, noChangesCount, maxNoChangesBeforeClose int, rationale, acceptance, projectRoot string) (bool, string, error) {
1318		if w.SatisfactionChecker != nil {
1319			return w.SatisfactionChecker.CheckSatisfied(ctx, beadID, noChangesCount)
1320		}
1321		candidate := false
1322		evidence := ""
1323		switch {
1324		case rationaleIsSpecific(rationale):
1325			candidate = true
1326			evidence = rationale
1327		case noChangesCount >= maxNoChangesBeforeClose:
1328			candidate = true
1329			evidence = fmt.Sprintf("no_changes on %d consecutive attempt(s); bead treated as already satisfied", noChangesCount)
1330		}
1331		if !candidate {
1332			return false, "", nil
1333		}
1334		// Tighten the gate: when AC names structural properties (test functions,
1335		// deleted files, removed struct fields), refuse already_satisfied unless
1336		// each property holds in the worktree / rationale. Prevents false closes
1337		// where a regression suite passes but the AC's specific contract is unmet.
1338		if claims := ParseACClaims(acceptance); len(claims) > 0 {
1339			if ok, why := VerifyACClaims(claims, projectRoot, rationale); !ok {
1340				return false, why, nil
1341			}
1342		}
1343		return true, evidence, nil
1344	}
1345	
1346	func shouldSuppressNoProgress(report ExecuteBeadReport) bool {
1347		if report.BaseRev == "" || report.ResultRev == "" {
1348			return false
1349		}
1350		return report.BaseRev == report.ResultRev
1351	}
