1353	// classifyReviewError maps a reviewer error and partial result into one of the
1354	// four FEAT-022 §12 taxonomy classes. Resolution order:
1355	//  1. reviewRes.Error if it's already one of the canonical class identifiers
1356	//     (the reviewer set it explicitly — preferred path).
1357	//  2. The error string text (for backwards-compatible reviewers that only
1358	//     embed the class in their message).
1359	//  3. ErrReviewVerdictUnparseable as a fallback when the strict-parse error
1360	//     leaks through a reviewer that did not set Error.
1361	//  4. Default to transport (network/provider-side failure) when nothing else
1362	//     matches.
1363	func classifyReviewError(reviewErr error, reviewRes *ReviewResult) string {
1364		if reviewRes != nil {
1365			switch reviewRes.Error {
1366			case evidence.OutcomeReviewContextOverflow,
1367				evidence.OutcomeReviewProviderEmpty,
1368				evidence.OutcomeReviewUnparseable,
1369				evidence.OutcomeReviewTransport:
1370				return reviewRes.Error
1371			}
1372		}
1373		msg := ""
1374		if reviewErr != nil {
1375			msg = reviewErr.Error()
1376		}
1377		switch {
1378		case strings.Contains(msg, evidence.OutcomeReviewContextOverflow):
1379			return evidence.OutcomeReviewContextOverflow
1380		case strings.Contains(msg, evidence.OutcomeReviewProviderEmpty):
1381			return evidence.OutcomeReviewProviderEmpty
1382		case strings.Contains(msg, evidence.OutcomeReviewUnparseable):
1383			return evidence.OutcomeReviewUnparseable
1384		case strings.Contains(msg, evidence.OutcomeReviewTransport):
1385			return evidence.OutcomeReviewTransport
1386		case reviewErr != nil && strings.Contains(msg, ErrReviewVerdictUnparseable.Error()):
1387			return evidence.OutcomeReviewUnparseable
1388		}
1389		return evidence.OutcomeReviewTransport
1390	}
1391	
1392	// reResultRevField extracts the result_rev value from a structured review-error
1393	// event body (one `result_rev=<sha>` line per event, written by
1394	// reviewErrorEventBody). The format is intentionally line-oriented so it
1395	// survives the AppendEvent body cap without losing the rev association.
1396	var reResultRevField = regexp.MustCompile(`(?m)^result_rev=([^\s]+)\s*$`)
1397	
1398	// countPriorReviewErrors returns the number of `review-error` events already
1399	// recorded against this bead whose body cites the given result_rev. This is
1400	// the FEAT-022 §14 retry counter — it is event-scoped (no separate counter
1401	// field on the bead) so a fresh result_rev naturally resets the count.
1402	func countPriorReviewErrors(store ExecuteBeadLoopStore, beadID, resultRev string) int {
1403		if resultRev == "" {
1404			return 0
1405		}
1406		events, err := store.Events(beadID)
1407		if err != nil {
1408			return 0
1409		}
1410		n := 0
1411		for _, ev := range events {
1412			if ev.Kind != "review-error" {
1413				continue
1414			}
1415			m := reResultRevField.FindStringSubmatch(ev.Body)
1416			if m == nil {
1417				continue
1418			}
1419			if m[1] == resultRev {
1420				n++
1421			}
1422		}
1423		return n
1424	}
1425	
1426	// reviewErrorEventBody is the canonical body shape for review-error and
1427	// review-manual-required events. It carries the failure class, attempt count,
1428	// and result_rev as discrete lines so operators can grep without parsing the
1429	// full reviewer error text. The trailing free-form message is the raw
1430	// reviewer-error string for forensics.
1431	func reviewErrorEventBody(class string, attemptCount int, resultRev, message string) string {
1432		var b strings.Builder
1433		fmt.Fprintf(&b, "failure_class=%s\n", class)
1434		fmt.Fprintf(&b, "attempt_count=%d\n", attemptCount)
1435		fmt.Fprintf(&b, "result_rev=%s\n", resultRev)
1436		if message != "" {
1437			b.WriteString("\n")
1438			b.WriteString(message)
1439		}
1440		return b.String()
1441	}
1442	
1443	// shouldAttemptConflictRecovery returns true when the loop should try to reuse
1444	// a preserved iteration ref before discarding it. Requires a non-empty
1445	// ProjectRoot so recovery git commands have a working directory, and a
1446	// non-empty PreserveRef to actually have something to recover.
1447	func shouldAttemptConflictRecovery(report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime) bool {
1448		if report.PreserveRef == "" || runtime.ProjectRoot == "" {
1449			return false
1450		}
1451		switch report.Status {
1452		case ExecuteBeadStatusLandConflict:
1453			return true
1454		case ExecuteBeadStatusExecutionFailed:
1455			// Attempt recovery when a commit was produced before the failure (e.g.
1456			// agent timed out mid-run). Both BaseRev and ResultRev must be set and
1457			// differ, because an empty BaseRev means we cannot confirm the agent
1458			// made any progress beyond the starting point.
1459			return report.BaseRev != "" && report.ResultRev != "" && report.ResultRev != report.BaseRev
1460		}
1461		return false
1462	}
1463	
1464	// runConflictRecovery attempts to recover a preserved iteration before the loop
1465	// parks the bead as failed. Step 1: 3-way ort auto-merge (-X ours). Step 2 (if
1466	// step 1 fails and ConflictResolver is set): focused conflict-resolve agent.
1467	// Returns an updated ExecuteBeadReport whose Status is success when recovery
1468	// landed the commit, or land_conflict_unresolvable/land_conflict_needs_human
1469	// when all recovery paths failed.
1470	func (w *ExecuteBeadWorker) runConflictRecovery(
1471		ctx context.Context,
1472		b bead.Bead,
1473		report ExecuteBeadReport,
1474		runtime ExecuteBeadLoopRuntime,
1475		assignee string,
1476		now func() time.Time,
1477	) ExecuteBeadReport {
1478		var gitOps LandingGitOps = RealLandingGitOps{}
1479	
1480		autoFn := w.conflictAutoRecoverFn
1481		if autoFn == nil {
1482			autoFn = landConflictAutoRecover
1483		}
1484		newTip, autoErr := autoFn(runtime.ProjectRoot, report.PreserveRef, gitOps)
1485		if autoErr == nil && newTip != "" {
1486			_ = w.Store.AppendEvent(b.ID, bead.BeadEvent{
1487				Kind:      "land-conflict-auto-recovered",
1488				Summary:   "preserved iteration auto-recovered onto current tip via ort",
1489				Body:      fmt.Sprintf("preserve_ref=%s\nnew_tip=%s", report.PreserveRef, newTip),
1490				Actor:     assignee,
1491				Source:    "ddx agent execute-loop",
1492				CreatedAt: now().UTC(),
1493			})
1494			report.Status = ExecuteBeadStatusSuccess
1495			report.ResultRev = newTip
1496			report.Detail = "auto-recovered: merged preserved iteration onto current tip via ort"
1497			return report
1498		}
1499	
1500		if w.ConflictResolver != nil {
1501			resolvedTip, isBlocking, resolveErr := w.ConflictResolver(ctx, b.ID, report.PreserveRef, runtime.ProjectRoot)
1502			if resolveErr == nil && resolvedTip != "" {
